// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const nameError = name.trim() === '' ? 'Name is required' : '';
  const emailError = useMemo(() => {
    if (email.trim() === '') return 'Email is required';
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email) ? '' : 'Please enter a valid email address';
  }, [email]);

  const isStep1Valid = nameError === '' && emailError === '';
  const isStep2Valid = satisfaction !== '';
  const isStep3Valid = true;
  const isStep4Valid = true;

  const canProceedToNext = useMemo(() => {
    if (currentStep === 1) return isStep1Valid;
    if (currentStep === 2) return isStep2Valid;
    if (currentStep === 3) return isStep3Valid;
    return isStep4Valid;
  }, [currentStep, isStep1Valid, isStep2Valid, isStep3Valid, isStep4Valid]);

  const handleNext = useCallback(() => {
    if (currentStep < 4 && canProceedToNext) {
      setCurrentStep(currentStep + 1);
    }
  }, [currentStep, canProceedToNext]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments: comments.trim(),
    });
  }, [name, email, satisfaction, features, comments, submit]);

  const satisfactionOptions = props.satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label: `${index + 1} - ${label}`,
  }));

  const featureCheckboxes = props.featureOptions.map((feature) => ({
    label: feature,
    checked: features.includes(feature),
  }));

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Progress Bar */}
        <Box>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
            Step {currentStep} of 4
          </Text>
          <Progress value={currentStep} max={4} size="md" showLabel={false} />
        </Box>

        {/* Step 1: Name and Email */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Personal Information</Heading>
              <Input
                label="Name"
                required
                value={name}
                onChange={setName}
                placeholder="Enter your full name"
                error={nameError}
              />
              <Input
                label="Email"
                required
                type="email"
                value={email}
                onChange={setEmail}
                placeholder="Enter your email address"
                error={emailError}
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={satisfaction}
                onChange={setSatisfaction}
                options={satisfactionOptions}
                direction="horizontal"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Which features interest you?</Heading>
              <Stack gap="var(--ggui-spacing-2)">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={(checked) => {
                      if (checked) {
                        setFeatures([...features, feature]);
                      } else {
                        setFeatures(features.filter((f) => f !== feature));
                      }
                    }}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Comments"
                value={comments}
                onChange={setComments}
                placeholder="Share any additional thoughts or feedback..."
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Review Step */}
        {currentStep === 4 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" border={true}>
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review Your Answers</Heading>
              <Divider />
              <Stack gap="var(--ggui-spacing-3)">
                <Box>
                  <Text variant="label">Name</Text>
                  <Text>{name}</Text>
                </Box>
                <Box>
                  <Text variant="label">Email</Text>
                  <Text>{email}</Text>
                </Box>
                <Box>
                  <Text variant="label">Satisfaction</Text>
                  <Text>
                    {satisfaction ? `${satisfaction} - ${props.satisfactionLabels[parseInt(satisfaction, 10) - 1]}` : 'Not selected'}
                  </Text>
                </Box>
                <Box>
                  <Text variant="label">Interested Features</Text>
                  <Text>{features.length > 0 ? features.join(', ') : 'None selected'}</Text>
                </Box>
                <Box>
                  <Text variant="label">Comments</Text>
                  <Text>{comments || '(No comments provided)'}</Text>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="between" align="center">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          <Stack direction="horizontal" gap="var(--ggui-spacing-2)">
            {currentStep < 4 && (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={!canProceedToNext}
              >
                Next
              </Button>
            )}
            {currentStep === 4 && (
              <Button
                variant="primary"
                onClick={handleSubmit}
              >
                Submit
              </Button>
            )}
          </Stack>
        </Row>
      </Stack>
    </Container>
  );
}
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // State for tasks and UI
  const [localTasks, setLocalTasks] = useState(props.tasks || []);
  const [addingTaskColumn, setAddingTaskColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTaskTitle, setEditingTaskTitle] = useState('');

  // Handle real-time task updates from stream
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'create' && task) {
        setLocalTasks(prev => [...prev, { id: task.id || `task-${Date.now()}`, title: task.title, priority: task.priority, assignee: task.assignee, column: task.column, dueDate: task.dueDate }]);
      } else if (action === 'move' && task) {
        setLocalTasks(prev => prev.map(t => t.id === task.id ? { ...t, column: task.column } : t));
      } else if (action === 'edit' && task) {
        setLocalTasks(prev => prev.map(t => t.id === task.id ? { ...t, title: task.title, priority: task.priority } : t));
      } else if (action === 'delete' && task?.id) {
        setLocalTasks(prev => prev.filter(t => t.id !== task.id));
      }
    }
  }, [taskChanged.latest]);

  // Compute task counts per column
  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, typeof localTasks> = {};
    (props.columns || []).forEach(col => {
      grouped[col.id || ''] = [];
    });
    localTasks.forEach(task => {
      const colId = task.column || 'todo';
      if (!grouped[colId]) grouped[colId] = [];
      grouped[colId].push(task);
    });
    return grouped;
  }, [localTasks, props.columns]);

  const totalTasks = localTasks.length;
  const completedTasks = tasksByColumn['done']?.length || 0;

  // Handlers
  const handleAddTask = useCallback((columnId: string) => {
    if (newTaskTitle.trim()) {
      const newTask = {
        id: `task-${Date.now()}`,
        title: newTaskTitle,
        priority: newTaskPriority,
        column: columnId,
      };
      setLocalTasks(prev => [...prev, newTask]);
      taskUpdate({ action: 'create', taskId: newTask.id, data: { column: columnId } });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddingTaskColumn(null);
    }
  }, [newTaskTitle, newTaskPriority, taskUpdate]);

  const handleMoveTask = useCallback((taskId: string, toColumn: string) => {
    setLocalTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: toColumn } : t));
    taskUpdate({ action: 'move', taskId, data: { column: toColumn } });
  }, [taskUpdate]);

  const handleEditTask = useCallback((taskId: string) => {
    if (editingTaskTitle.trim()) {
      setLocalTasks(prev => prev.map(t => t.id === taskId ? { ...t, title: editingTaskTitle } : t));
      taskUpdate({ action: 'edit', taskId, data: { column: localTasks.find(t => t.id === taskId)?.column || 'todo' } });
      setEditingTaskId(null);
      setEditingTaskTitle('');
    }
  }, [editingTaskTitle, localTasks, taskUpdate]);

  const priorityColor = (priority?: string) => {
    switch (priority) {
      case 'high': return 'var(--ggui-color-error-500)';
      case 'medium': return 'var(--ggui-color-warning-500)';
      case 'low': return 'var(--ggui-color-success-500)';
      default: return 'var(--ggui-color-outline)';
    }
  };

  return (
    <Stack gap="var(--ggui-spacing-6)">
      {/* Summary Bar */}
      <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-lg)">
        <Row justify="between" align="center">
          <Text variant="label" color="var(--ggui-color-primary-900)">
            Total Tasks: {totalTasks}
          </Text>
          <Text variant="label" color="var(--ggui-color-success-700)">
            Completed: {completedTasks}
          </Text>
        </Row>
      </Box>

      {/* Kanban Board */}
      <Row gap="var(--ggui-spacing-4)" align="start">
        {(props.columns || []).map(column => (
          <Card key={column.id} padding="var(--ggui-spacing-4)" shadow="sm" style={{ flex: '1 1 300px', minHeight: '500px' }}>
            {/* Column Header */}
            <Row justify="between" align="center">
              <Heading level={4}>{column.name}</Heading>
              <Badge variant="secondary" size="sm">
                {(tasksByColumn[column.id || ''] || []).length}
              </Badge>
            </Row>

            <Divider orientation="horizontal" margin="0" color="var(--ggui-color-outline)" />

            {/* Task List */}
            <Stack gap="var(--ggui-spacing-2)" style={{ flex: 1 }}>
              {(tasksByColumn[column.id || ''] || []).map(task => (
                <Card
                  key={task.id}
                  padding="var(--ggui-spacing-3)"
                  shadow="sm"
                  as={Pressable}
                  onPress={() => setEditingTaskId(task.id || '')}
                  style={{ cursor: 'pointer', background: 'var(--ggui-color-surfaceVariant)' }}
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    {editingTaskId === task.id ? (
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task Title"
                          value={editingTaskTitle}
                          onChange={setEditingTaskTitle}
                          placeholder="Edit task..."
                        />
                        <Row gap="var(--ggui-spacing-2)" justify="end">
                          <Button variant="ghost" size="sm" onClick={() => setEditingTaskId(null)}>
                            Cancel
                          </Button>
                          <Button variant="primary" size="sm" onClick={() => handleEditTask(task.id || '')}>
                            Save
                          </Button>
                        </Row>
                      </Stack>
                    ) : (
                      <>
                        <Text variant="body" weight="semibold" truncate>
                          {task.title || 'Untitled'}
                        </Text>
                        <Row gap="var(--ggui-spacing-2)" align="center">
                          <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'success'} size="sm">
                            {task.priority || 'medium'}
                          </Badge>
                          {task.assignee && (
                            <Avatar name={task.assignee} size="xs" />
                          )}
                        </Row>
