  // Color map for element categories
  const categoryColors: Record<string, string> = {
    'alkali-metal': 'var(--ggui-color-primary-100)',
    'alkaline-earth-metal': 'var(--ggui-color-primary-200)',
    'transition-metal': 'var(--ggui-color-info-100)',
