                </Text>
                <Text variant="label" weight="bold" color="var(--ggui-color-onSurface)" align="center">
                  {el.symbol}
                </Text>
              </Stack>
            </Card>
          ))}
        </Card>

        {/* Element detail panel */}
        {selectedElement && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" role="region" aria-live="polite" aria-label="Element details">
            <Stack gap="var(--ggui-spacing-4)">
              <Stack gap="var(--ggui-spacing-2)">
                <Row justify="between" align="center">
                  <Heading level={2}>{selectedElement.name}</Heading>
                  <Button variant="ghost" size="sm" onClick={() => setSelectedElement(null)} rightIcon={<Icon name="x" size={18} />} />
                </Row>
