              </Stack>
              <Divider />
              <Stack gap="var(--ggui-spacing-3)">
                <Row justify="between">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Number</Text>
                  <Text variant="body" color="var(--ggui-color-onSurface)">{selectedElement.atomicNumber}</Text>
                </Row>
                <Row justify="between">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text>
                  <Text variant="body" color="var(--ggui-color-onSurface)">{selectedElement.atomicWeight?.toFixed(3)}</Text>
                </Row>
                {selectedElement.category && (
                  <Row justify="between">
