/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State management
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Computed values
  const maxQuantity = props.product.stock || 1;
  const isOutOfStock = !props.product.stock || props.product.stock === 0;
  const stockStatus = !props.product.stock || props.product.stock === 0
    ? 'Out of Stock'
    : props.product.stock < 10
    ? 'Low Stock'
    : 'In Stock';
  const stockBadgeVariant = !props.product.stock || props.product.stock === 0
    ? 'error'
    : props.product.stock < 10
    ? 'warning'
    : 'success';

  // Handlers
  const handleIncrement = useCallback(() => {
    setQuantity((prev) => Math.min(prev + 1, maxQuantity));
  }, [maxQuantity]);

  const handleDecrement = useCallback(() => {
    setQuantity((prev) => Math.max(prev - 1, 1));
  }, []);

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product.id, quantity, addToCart]);

  // Helper: render star rating
  const renderStars = (rating: number | undefined, label?: string) => {
    if (!rating) return null;
    const stars = [];
    const ariaLabel = label || `Rating: ${rating.toFixed(1)} out of 5 stars`;
    for (let i = 1; i <= 5; i++) {
      const isFilled = i <= rating;
      stars.push(
        <Icon
          key={i}
          name={isFilled ? 'star' : 'star'}
          size={16}
          color={isFilled ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outlineVariant)'}
          style={{ opacity: isFilled ? 1 : 0.3 }}
        />
      );
    }
    return <Row gap="var(--ggui-spacing-1)" align="center" style={{ position: 'relative' }} aria-label={ariaLabel}>{stars}</Row>;
  };

  // Helper: format price
  const formatPrice = (price: number | undefined, currency: string | undefined) => {
    if (price === undefined) return 'N/A';
    const currencySymbol = currency || 'USD';
    return `${currencySymbol} ${price.toFixed(2)}`;
  };

  // Helper: render specifications as table
  const getSpecificationsTable = () => {
    if (!props.product.specifications || props.product.specifications.length === 0) {
      return <Text color="var(--ggui-color-onSurfaceVariant)">No specifications available.</Text>;
    }
    const specs = props.product.specifications as Array<{ key?: string; value?: string }>;
    return (
      <Table
        columns={[
          { key: 'key', header: 'Specification', width: '40%' },
          { key: 'value', header: 'Value', width: '60%' },
        ]}
        data={specs}
      />
    );
  };

  // Helper: render reviews
  const getReviews = () => {
    if (!props.product.reviews || props.product.reviews.length === 0) {
      return <Text color="var(--ggui-color-onSurfaceVariant)">No reviews yet.</Text>;
    }
    const reviews = props.product.reviews as Array<{ author?: string; rating?: number; text?: string; date?: string }>;
    return (
      <Stack gap="var(--ggui-spacing-4)">
         {reviews.map((review, idx) => (
           <Card key={idx} padding="var(--ggui-spacing-4)" border={true} shadow="sm" as={Hoverable} hoverStyle={{ boxShadow: 'var(--ggui-shape-shadow-md)', cursor: 'pointer' }}>
             <Stack gap="var(--ggui-spacing-2)">
               <Stack direction="horizontal" align="center" justify="between" gap="var(--ggui-spacing-3)">
                 <Text variant="label">{review.author || 'Anonymous'}</Text>
                 <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{review.date || 'N/A'}</Text>
               </Stack>
               <Row gap="var(--ggui-spacing-1)" align="center">
                 {renderStars(review.rating, `Review rating: ${review.rating?.toFixed(1) || 0} out of 5 stars`)}
               </Row>
               <Text variant="body">{review.text || ''}</Text>
             </Stack>
           </Card>
         ))}
      </Stack>
    );
  };

  // Tab items
  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Text variant="body" color="var(--ggui-color-onSurface)">
          {props.product.description || 'No description available.'}
        </Text>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: getSpecificationsTable(),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: getReviews(),
    },
  ];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
         {/* TOP SECTION: Image & Product Details */}
         <Card padding="var(--ggui-spacing-4)" shadow="md">
           <Stack direction="horizontal" gap="var(--ggui-spacing-6)" align="start">
             {/* Product Image Placeholder */}
             <Box
               as={Clickable}
               onClick={() => {}}
               background="var(--ggui-color-primary-100)"
               borderRadius="var(--ggui-shape-radius-lg)"
               padding="var(--ggui-spacing-6)"
               style={{ minWidth: 'var(--ggui-spacing-12)', width: 'var(--ggui-spacing-12)', aspectRatio: '1 / 1', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
               aria-label={`Product image: ${props.product.name || 'Product'}`}
               role="button"
             >
               <Stack align="center" justify="center" gap="var(--ggui-spacing-3)">
                 <Icon name="image" size={64} color="var(--ggui-color-primary-600)" />
                 <Text variant="bodySmall" color="var(--ggui-color-primary-700)" align="center">
                   {props.product.name || 'Product Image'}
                 </Text>
               </Stack>
             </Box>

             {/* Product Details */}
             <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1 }}>
               {/* Title */}
               <Heading level={1}>{props.product.name || 'Untitled Product'}</Heading>

               {/* Price */}
               <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-primary-600)">
                 {formatPrice(props.product.price, props.product.currency)}
               </Text>

               {/* Rating & Review Count */}
               <Row align="center" gap="var(--ggui-spacing-3)">
                 {renderStars(props.product.rating, `Rating: ${props.product.rating?.toFixed(1) || 0} out of 5 stars`)}
                 <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                   ({props.product.reviewCount || 0} reviews)
                 </Text>
               </Row>

               {/* Stock Status Badge */}
               <Badge variant={stockBadgeVariant}>{stockStatus}</Badge>
             </Stack>
           </Stack>
         </Card>

         {/* MIDDLE SECTION: Tabs */}
         <Divider margin="var(--ggui-spacing-4)" />
         <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surface)">
           <Tabs
             items={tabItems}
             activeKey={activeTab}
             onChange={setActiveTab}
             variant="line"
             size="md"
           />
         </Box>

         {/* BOTTOM SECTION: Quantity & Add to Cart */}
         <Divider margin="var(--ggui-spacing-4)" />
         <Stack gap="var(--ggui-spacing-4)" direction="horizontal" align="center" style={{ flexWrap: 'wrap' }}>
           {/* Quantity Selector */}
           <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
             <label htmlFor="qty-input" style={{ display: 'contents', fontWeight: 'var(--ggui-font-weight-medium)', fontSize: 'var(--ggui-font-size-sm)' }}>
               <Text variant="label">Quantity:</Text>
             </label>
             <Button
               variant="outline"
               size="sm"
               onClick={handleDecrement}
               disabled={quantity <= 1}
               aria-label="Decrease quantity"
             >
               −
             </Button>
             <Input
               id="qty-input"
               label="" 
               type="number"
               value={String(quantity)}
               onChange={(val) => {
                 const num = parseInt(val, 10);
                 if (!isNaN(num) && num >= 1 && num <= maxQuantity) {
                   setQuantity(num);
                 }
               }}
               disabled={isOutOfStock}
               style={{ width: 'var(--ggui-spacing-8)', textAlign: 'center' }}
             />
             <Button
               variant="outline"
               size="sm"
               onClick={handleIncrement}
               disabled={quantity >= maxQuantity}
               aria-label="Increase quantity"
             >
               +
             </Button>
           </Stack>

           {/* Add to Cart Button */}
           <Button
             variant="primary"
             size="md"
             onClick={handleAddToCart}
             disabled={isOutOfStock}
           >
             Add to Cart
           </Button>
         </Stack>
      </Stack>
    </Container>
  );
}

