  // Group consecutive messages from the same sender
  const groupedMessages = useMemo(() => {
    const grouped: Array<{ sender?: string; messages: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    messages.forEach((msg) => {
      const lastGroup = grouped[grouped.length - 1];
      if (lastGroup && lastGroup.sender === msg.sender) {
        lastGroup.messages.push(msg);
      } else {
        grouped.push({ sender: msg.sender, messages: [msg] });
      }
    });
    return grouped;
  }, [messages]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: inputValue, timestamp });
      setInputValue('');
    }
  }, [inputValue, sendMessage]);

  // Handle Enter key in input
  const handleKeyPress = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  // Format timestamp for display
  const formatTime = (timestamp?: string) => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
