            <Row justify="between" align="center" gap="var(--ggui-spacing-3)">
              <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                <Heading level={3} color="var(--ggui-color-primary-900)">{props.title}</Heading>
              </Stack>
              <Badge variant="primary" size="md">
                {props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}
              </Badge>
            </Row>
          </Box>

          {/* Message List */}
          {/* Message List */}
          <Box
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-md)"
            padding="var(--ggui-spacing-4)"
            style={{
              minHeight: '400px',
              maxHeight: '500px',
              overflowY: 'auto',
              display: 'flex',
              flexDirection: 'column',
            }}
          >
            {groupedMessages.length === 0 ? (
              <Box
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  height: '100%',
                }}
              >
                <Text color="var(--ggui-color-onSurfaceVariant)" align="center">
                  No messages yet. Start the conversation!
                </Text>
              </Box>
            ) : (
              <>
                {groupedMessages.map((group, groupIdx) => {
                  const isCurrentUser = group.sender === props.currentUser;
                  return (
                    <article
                      key={`group-${groupIdx}`}
                      aria-label={`Message from ${group.sender || 'Unknown'}`}
                    >
                      <Stack
                        gap="var(--ggui-spacing-1)"
