                          >
                            {group.sender}
                          </Text>
                        )}
                        {group.messages.map((msg, msgIdx) => (
                          <Box
                            key={`msg-${groupIdx}-${msgIdx}`}
                            background={
                              isCurrentUser
                                ? 'var(--ggui-color-primary-600)'
                                : 'var(--ggui-color-surfaceVariant)'
                            }
                            padding="var(--ggui-spacing-3)"
                            borderRadius="var(--ggui-shape-radius-lg)"
                            style={{
                              maxWidth: '70%',
                              wordWrap: 'break-word',
                            }}
                          >
                            <Stack gap="var(--ggui-spacing-1)" align="start">
                              <Text
                                color={
                                  isCurrentUser
                                    ? 'var(--ggui-color-primary-50)'
                                    : 'var(--ggui-color-onSurface)'
                                }
                                variant="body"
                              >
                                {msg.text}
                              </Text>
                              {msg.timestamp && (
                                <time dateTime={msg.timestamp}>
                                  <Text
                                    size="xs"
                                    color={
                                      isCurrentUser
                                        ? 'var(--ggui-color-primary-100)'
                                        : 'var(--ggui-color-onSurfaceVariant)'
                                    }
                                  >
                                    {formatTime(msg.timestamp)}
