                            </Stack>
                          </Box>
                        ))}
                      </Stack>
                    </article>
                  );
                })}
              </>
            )}

            {/* Typing Indicator */}
            {typingIndicator && (
              <div aria-live="polite" aria-atomic="true">
                <Stack gap="var(--ggui-spacing-1)" align="start">
                  <Box
                    background="var(--ggui-color-surfaceVariant)"
                    padding="var(--ggui-spacing-3)"
                    borderRadius="var(--ggui-shape-radius-lg)"
                    style={{
                      display: 'flex',
                      alignItems: 'center',
                      gap: 'var(--ggui-spacing-2)',
                    }}
                  >
                    <Spinner size={16} color="var(--ggui-color-onSurfaceVariant)" />
                    <Text color="var(--ggui-color-onSurfaceVariant)" size="sm">
