}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // Wire hooks — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate');
  const marketStatus = useStream<StreamMarketStatus>('marketStatus');

  // State: merge initial stocks with stream updates
  const [stocks, setStocks] = useState(props.stocks || []);
  const lastUpdateRef = useRef<Date>(new Date());

  // Effect: apply price updates from stream
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      setStocks((prevStocks) =>
        prevStocks.map((stock) =>
          stock.symbol === update.symbol
            ? {
                ...stock,
                price: update.price ?? stock.price,
                change: update.change ?? stock.change,
                changePercent: update.changePercent ?? stock.changePercent,
              }
            : stock
        )
      );
      lastUpdateRef.current = new Date();
    }
  }, [priceUpdate.latest]);

  // Get current time for last updated timestamp
  const [currentTime, setCurrentTime] = useState(new Date());
  useEffect(() => {
    const interval = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(interval);
  }, []);

  // Market status from stream
  const marketIsOpen = marketStatus.latest?.status === 'open';


  // Animation keys for flash effect on price updates
  const priceAnimationKeys = useMemo(() => {
    const keys: { [symbol: string]: number } = {};
    stocks.forEach((stock) => {
      keys[stock.symbol || ''] = 0;
    });
    return keys;
  }, [stocks.map((s) => s.symbol).join(',')]);
  return (
    <Container maxWidth='2xl' padding='var(--ggui-spacing-6)'>
      <Stack gap='var(--ggui-spacing-6)'>
        {/* Header Section */}
        <Stack direction='horizontal' justify='between' align='center'>
          <Heading level={1} color='var(--ggui-color-onSurface)'>
            Market Watch
          </Heading>
          <Stack direction='horizontal' gap='var(--ggui-spacing-3)' align='center'>
            <Text variant='caption' color='var(--ggui-color-onSurfaceVariant)'>
              Last Updated: {currentTime.toLocaleTimeString()}
            </Text>
            <Badge
              variant={marketIsOpen ? 'success' : 'warning'}
              size='sm'
            >
              {marketStatus.latest?.status || 'unknown'}
            </Badge>
          </Stack>
        </Stack>

        {/* Stock Cards Grid */}
        {/* Stock Cards Grid */}
        <MotionKeyframes />
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            gap: 'var(--ggui-spacing-4)',
          }}
        >
          {stocks.length === 0 ? (
            <Text variant='body' color='var(--ggui-color-onSurfaceVariant)'>
              No stocks to display
            </Text>
          ) : (
            stocks.map((stock) => {
              const isPositive = (stock.changePercent ?? 0) >= 0;
              const changeColor = isPositive
                ? 'var(--ggui-color-success-600)'
                : 'var(--ggui-color-error-600)';
              const borderColor = isPositive
                ? 'var(--ggui-color-success-200)'
                : 'var(--ggui-color-error-200)';

              return (
                <Card
                  key={`${stock.symbol}-${priceAnimationKeys[stock.symbol || '']}`}
                  padding='var(--ggui-spacing-4)'
                  shadow='md'
                  radius='lg'
                  border={false}
                  style={{
                    borderLeft: `4px solid ${borderColor}`,
                    transition: 'all 0.2s ease-in-out',
                    animation: `ggui-flash 600ms ease-out`,
                    '--ggui-flash-color': isPositive
                      ? 'var(--ggui-color-success-100)'
                      : 'var(--ggui-color-error-100)',
                  } as React.CSSProperties}
>
                  <Stack gap='var(--ggui-spacing-3)'>
                    {/* Ticker Symbol */}
                    <Heading
                      level={3}
                      color='var(--ggui-color-onSurface)'
                      style={{
                        fontSize: 'var(--ggui-font-size-2xl)',
                        fontWeight: 'var(--ggui-font-weight-bold)',
                        margin: 0,
                      }}
                    >
                      {stock.symbol || 'N/A'}
                    </Heading>

                    {/* Company Name */}
                    <Text
                      variant='body'
                      color='var(--ggui-color-onSurfaceVariant)'
                      style={{ margin: 0 }}
                    >
                      {stock.name || 'Unknown'}
                    </Text>

                    {/* Price */}
                    <Text
                      variant='bodyLarge'
                      color='var(--ggui-color-onSurface)'
                      weight='semibold'
                      style={{ margin: 0 }}
                    >
                      ${(stock.price ?? 0).toFixed(2)}
                    </Text>

                    {/* Change Amount and Percentage */}
                    <Stack direction='horizontal' gap='var(--ggui-spacing-2)' align='center'>
                      <Icon
                        name={isPositive ? 'trending-up' : 'trending-down'}
                        size={16}
                        color={changeColor}
                      />
                      <Text
                        variant='body'
                        color={changeColor}
                        weight='semibold'
                        style={{ margin: 0 }}
                      >
                        {isPositive ? '+' : ''}{(stock.change ?? 0).toFixed(2)} ({(stock.changePercent ?? 0).toFixed(2)}%)
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })
          )}
        </div>
      </Stack>
    </Container>
  );
}

