interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // State for all three steps
  const [currentStep, setCurrentStep] = useState(1);
  const [profile, setProfile] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || props.avatarOptions[0] || '',
    role: props.initialProfile.role || '',
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: props.initialProfile.theme || 'light',
  });

  // Validation
  const isEmailValid = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const isStep1Valid = profile.name.trim().length > 0 && isEmailValid(profile.email);
  const isStep2Valid = profile.role.length > 0;

  const canProceed = currentStep === 1 ? isStep1Valid : currentStep === 2 ? isStep2Valid : true;

  const handleFieldChange = (field: string, value: string | boolean) => {
    setProfile(prev => ({ ...prev, [field]: value }));
  };

  const handleNext = () => {
    if (canProceed && currentStep < 3) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleComplete = () => {
    complete({
      name: profile.name,
      email: profile.email,
      avatar: profile.avatar,
      role: profile.role,
      emailNotifications: profile.emailNotifications,
      theme: profile.theme,
    });
  };

  const progressPercent = ((currentStep - 1) / 2) * 100;

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-10)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Header with step indicator */}
        <Stack gap="var(--ggui-spacing-3)">
          <Heading level={2}>Profile Setup</Heading>
          <Stack gap="var(--ggui-spacing-2)">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Step {currentStep} of 3</Text>
            <Progress value={progressPercent} max={100} size="md" />
          </Stack>
        </Stack>

        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Input
                label="Name"
                value={profile.name}
                onChange={(value) => handleFieldChange('name', value)}
                placeholder="Enter your name"
                required
                error={profile.name.trim().length === 0 && profile.name.length > 0 ? 'Name is required' : ''}
              />
              <Input
                label="Email"
                type="email"
                value={profile.email}
                onChange={(value) => handleFieldChange('email', value)}
                placeholder="you@example.com"
                required
                error={profile.email.length > 0 && !isEmailValid(profile.email) ? 'Invalid email format' : ''}
              />
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Avatar</Text>
                <Row gap="var(--ggui-spacing-3)" wrap>
                  {props.avatarOptions.map((emoji) => (
                    <Box
                      key={emoji}
                      as={Clickable}
                      onClick={() => handleFieldChange('avatar', emoji)}
                      padding="var(--ggui-spacing-2)"
                      borderRadius="var(--ggui-shape-radius-lg)"
                      background={profile.avatar === emoji ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'}
                      style={{ cursor: 'pointer', transition: 'all 200ms ease' }}
                    >
                      <Text size="2xl">{emoji}</Text>
                    </Box>
                  ))}
                </Row>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Select
                label="Role"
                value={profile.role}
                onChange={(value) => handleFieldChange('role', value)}
                options={props.roleOptions.map(role => ({ value: role, label: role }))}
                placeholder="Select your role"
                required
              />
              <Toggle
                label="Email Notifications"
                checked={profile.emailNotifications}
                onChange={(checked) => handleFieldChange('emailNotifications', checked)}
              />
              <Toggle
                label="Dark Theme"
                checked={profile.theme === 'dark'}
                onChange={(checked) => handleFieldChange('theme', checked ? 'dark' : 'light')}
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Review & Confirm */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review Your Settings</Heading>
               <Box paddingY="var(--ggui-spacing-4)" paddingX="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                <Row justify="between" align="center">
                  <Text variant="label">Name</Text>
                  <Text>{profile.name}</Text>
                </Row>
                <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />
                <Row justify="between" align="center">
                  <Text variant="label">Email</Text>
                  <Text>{profile.email}</Text>
                </Row>
                <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />
                <Row justify="between" align="center">
                  <Text variant="label">Avatar</Text>
                  <Text size="xl">{profile.avatar}</Text>
                </Row>
                <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />
                <Row justify="between" align="center">
                  <Text variant="label">Role</Text>
                  <Text>{profile.role}</Text>
                </Row>
                <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />
                <Row justify="between" align="center">
                  <Text variant="label">Email Notifications</Text>
                   <Badge variant={profile.emailNotifications ? 'success' : 'default'}>{profile.emailNotifications ? 'On' : 'Off'}</Badge>
                </Row>
                <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />
                <Row justify="between" align="center">
                  <Text variant="label">Theme</Text>
                  <Text>{profile.theme === 'dark' ? 'Dark' : 'Light'}</Text>
                </Row>
               </Box>
            </Stack>
          </Card>
        )}

        {/* Navigation buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="between">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Go Back
          </Button>
          {currentStep < 3 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={!canProceed}
            >
              Next
            </Button>
          )}
          {currentStep === 3 && (
            <Button
              variant="primary"
              onClick={handleComplete}
            >
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

