  const [selectedDayIndex, setSelectedDayIndex] = useState<number>(0);
  const [showDetails, setShowDetails] = useState<boolean>(true);

  const normalizedCondition = useMemo(() => {
    return props.condition ? props.condition.toLowerCase() : '';
  }, [props.condition]);

  const getConditionEmoji = useCallback((condition: string) => {
    if (condition.includes('sun') || condition.includes('clear')) return '☀️';
    if (condition.includes('cloud') || condition.includes('overcast')) return '☁️';
    if (condition.includes('rain') || condition.includes('drizzle') || condition.includes('shower')) return '🌧️';
    if (condition.includes('storm') || condition.includes('thunder')) return '⛈️';
    if (condition.includes('snow') || condition.includes('sleet') || condition.includes('blizzard')) return '❄️';
    if (condition.includes('fog') || condition.includes('mist') || condition.includes('haze')) return '🌫️';
    if (condition.includes('wind')) return '💨';
    return '🌤️';
  }, []);

  const safeForecast = useMemo(() => {
    const source = Array.isArray(props.forecast) ? props.forecast.slice(0, 5) : [];
    const placeholdersNeeded = Math.max(0, 5 - source.length);
    const placeholders = Array.from({ length: placeholdersNeeded }, (_, index) => ({
      day: `Day ${source.length + index + 1}`
    }));
    return [...source, ...placeholders].slice(0, 5);
  }, [props.forecast]);

  useEffect(() => {
    if (selectedDayIndex > safeForecast.length - 1) {
      setSelectedDayIndex(0);
    }
  }, [safeForecast.length, selectedDayIndex]);

  const selectedForecast = safeForecast[selectedDayIndex] || null;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card
          padding="var(--ggui-spacing-6)"
          shadow="md"
          radius="xl"
          border
        >
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center" wrap>
              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">Current Weather</Text>
                <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>
              </Stack>
              <Badge variant="primary" size="md">{props.unit}</Badge>
            </Row>

            <Row justify="between" align="center" wrap>
              <Row align="center" gap="var(--ggui-spacing-3)">
                <Text
                  size="4xl"
                  weight="bold"
                  color="var(--ggui-color-primary-700)"
                >
                  {props.temperature}°{props.unit}
                </Text>
                <Text size="3xl" is="span" aria-label={props.condition}>
                  {getConditionEmoji(normalizedCondition)}
                </Text>
              </Row>
              <Stack align="end" gap="var(--ggui-spacing-1)">
                <Text variant="label" color="var(--ggui-color-onSurface)">{props.condition}</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Feels like live conditions</Text>
              </Stack>
            </Row>

            <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

            <Row gap="var(--ggui-spacing-6)" wrap>
              <Card padding="var(--ggui-spacing-3)" border radius="md" shadow="none">
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                  <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
                </Stack>
              </Card>
              <Card padding="var(--ggui-spacing-3)" border radius="md" shadow="none">
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                  <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface)">{props.windSpeed} km/h</Text>
                </Stack>
              </Card>
            </Row>

            <Row justify="between" align="center">
              <Text variant="label" color="var(--ggui-color-onSurface)">Show details</Text>
              <Toggle
                label="Weather detail visibility"
                checked={showDetails}
                onChange={setShowDetails}
                size="md"
              />
            </Row>

            {showDetails && selectedForecast && (
              <Alert variant="info" title={`Selected: ${selectedForecast.day || 'N/A'}`}>
                High {('high' in selectedForecast && selectedForecast.high !== undefined) ? selectedForecast.high : '-'}°{props.unit} • Low {('low' in selectedForecast && selectedForecast.low !== undefined) ? selectedForecast.low : '-'}°{props.unit}
              </Alert>
            )}
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg" border>
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={3} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
            {safeForecast.length === 0 ? (
              <Alert variant="warning" title="No forecast available">
                Forecast data is unavailable.
              </Alert>
            ) : (
              <Row gap="var(--ggui-spacing-2)" wrap aria-label="5-day forecast selection">
                {safeForecast.map((item, index) => {
                  const itemIcon = ('icon' in item && item.icon && item.icon.trim().length > 0) ? item.icon : getConditionEmoji(normalizedCondition);
                  const isSelected = selectedDayIndex === index;

                  return (
                    <Card
                      key={`${item.day || 'day'}-${index}`}
                      as={Clickable}
                      is="button"
                      onClick={() => setSelectedDayIndex(index)}
                      aria-selected={isSelected}
                      role="option"
                      hoverStyle={{ opacity: 0.92 }}
                      padding="var(--ggui-spacing-3)"
                      radius="md"
                      shadow="none"
                      border
                    >
                      <Stack gap="var(--ggui-spacing-1)" align="center">
                        <Text
                          variant="label"
                          color={isSelected ? 'var(--ggui-color-primary-700)' : 'var(--ggui-color-onSurface)'}
                        >
                          {item.day || 'N/A'}
                        </Text>
                        <Text size="2xl" is="span" aria-label={`Forecast icon for ${item.day || 'day'}`}>
                          {itemIcon}
                        </Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                          {('high' in item && item.high !== undefined) ? item.high : '-'}° / {('low' in item && item.low !== undefined) ? item.low : '-'}°
                        </Text>
                      </Stack>
                    </Card>
                  );
                })}
              </Row>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

