import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; dueDate?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board
  const [boardTasks, setBoardTasks] = useState<Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string }>>([]);
  const [addFormColumn, setAddFormColumn] = useState<string>('');
  const [newTaskTitle, setNewTaskTitle] = useState<string>('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');

  const [actionError, setActionError] = useState<string>('');
  const [streamError, setStreamError] = useState<string>('');
  useEffect(() => {
    const normalized = (props.tasks || []).map((task, index) => ({
      id: task.id && task.id.length > 0 ? task.id : `task-${index}-${String(task.title || 'untitled')}` ,
      title: task.title || 'Untitled task',
      priority: task.priority || 'low',
      assignee: task.assignee || 'NA',
      column: task.column || ((props.columns && props.columns[0] && props.columns[0].id) ? props.columns[0].id : 'todo'),
      dueDate: task.dueDate,
    }));
    setBoardTasks(normalized);
  }, [props.tasks, props.columns]);

  useEffect(() => {
    if (!taskChanged.latest) {
      return;
    }
    if (!taskChanged.latest.task) {
      setStreamError('Live update could not be applied: missing task payload.');
      return;
    }
    const incoming = taskChanged.latest.task;
    const incomingId = incoming.id || '';
    if (!incomingId) {
      setStreamError('Live update could not be applied: invalid task id.');
      return;
    }
    setStreamError('');
    setBoardTasks((prev) => {
      if (taskChanged.latest?.action === 'delete') {
        return prev.filter((task) => task.id !== incomingId);
      }
      const exists = prev.some((task) => task.id === incomingId);
      const normalizedTask = {
        id: incomingId,
        title: incoming.title || 'Untitled task',
        priority: incoming.priority || 'low',
        assignee: incoming.assignee || 'NA',
        column: incoming.column || ((props.columns && props.columns[0] && props.columns[0].id) ? props.columns[0].id : 'todo'),
        dueDate: incoming.dueDate,
      } as { id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string };
      if (!exists) {
        return [...prev, normalizedTask];
      }
      return prev.map((task) => (task.id === incomingId ? normalizedTask : task));
    });
  }, [taskChanged.latest, props.columns]);

  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string }>> = {};
    (props.columns || []).forEach((column) => {
      if (column.id) {
        grouped[column.id] = [];
      }
    });
    boardTasks.forEach((task) => {
      if (!grouped[task.column]) {
        grouped[task.column] = [];
      }
      grouped[task.column].push(task);
    });
    return grouped;
  }, [boardTasks, props.columns]);

  const completedColumnId = useMemo(() => {
    const doneColumn = (props.columns || []).find((column) => String(column.name || '').toLowerCase() === 'done');
    return doneColumn?.id || ((props.columns && props.columns[2] && props.columns[2].id) ? props.columns[2].id : 'done');
  }, [props.columns]);

  const completedCount = useMemo(() => {
    return boardTasks.filter((task) => task.column === completedColumnId).length;
  }, [boardTasks, completedColumnId]);

  const getPriorityVariant = useCallback((priority: 'low' | 'medium' | 'high') => {
    if (priority === 'high') return 'error';
    if (priority === 'medium') return 'warning';
    return 'success';
  }, []);

  const moveTask = useCallback((taskId: string, targetColumn: string) => {
    setActionError('');
    setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: targetColumn } : task)));
    try {
      taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
    } catch (_error) {
      setActionError('Task move update failed. Please retry.');
    }
  }, [taskUpdate]);

  const startEditTask = useCallback((taskId: string, currentTitle: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(currentTitle);
  }, []);

  const saveEditTask = useCallback((taskId: string) => {
    if (!editingTitle.trim()) {
      setEditingTaskId('');
      setEditingTitle('');
      return;
    }
    const taskToEdit = boardTasks.find((task) => task.id === taskId);
    if (!taskToEdit) {
      setEditingTaskId('');
      setEditingTitle('');
      return;
    }
    const updatedTask = { ...taskToEdit, title: editingTitle.trim() };
    setActionError('');
    setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? updatedTask : task)));
    try {
      taskUpdate({
        action: 'edit',
        taskId,
        data: {
          column: updatedTask.column,
          title: updatedTask.title,
          priority: updatedTask.priority,
          assignee: updatedTask.assignee,
          dueDate: updatedTask.dueDate || '',
        },
      });
    } catch (_error) {
      setActionError('Task edit update failed. Please retry.');
    }
    setEditingTaskId('');
    setEditingTitle('');
  }, [editingTitle, taskUpdate, boardTasks]);

  const createTask = useCallback((columnId: string) => {
    if (!newTaskTitle.trim()) {
      return;
    }
    const toDoColumnId = (props.columns || []).find((column) => String(column.name || '').toLowerCase() === 'to do')?.id || (props.columns[0]?.id || 'todo');
    const createdId = `task-${Date.now()}`;
    const createdTask = {
      id: createdId,
      title: newTaskTitle.trim(),
      priority: newTaskPriority,
      assignee: 'NA',
      column: toDoColumnId,
      dueDate: '',
    } as { id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string };
    setBoardTasks((prev) => [...prev, createdTask]);
    setActionError('');
    try {
      taskUpdate({
        action: 'create',
        taskId: createdId,
        data: {
          column: toDoColumnId,
          title: createdTask.title,
          priority: createdTask.priority,
          assignee: createdTask.assignee,
          dueDate: createdTask.dueDate || '',
        },
      });
    } catch (_error) {
      setActionError('Task create update failed. Please retry.');
    }
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddFormColumn(columnId);
  }, [newTaskTitle, newTaskPriority, props.columns, taskUpdate]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
