}


const CATEGORY_COLOR_MAP: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-100)',
  'alkaline earth metal': 'var(--ggui-color-warning-100)',
  'transition metal': 'var(--ggui-color-primary-100)',
  'post-transition metal': 'var(--ggui-color-info-100)',
  metalloid: 'var(--ggui-color-success-100)',
  nonmetal: 'var(--ggui-color-surfaceVariant)',
  halogen: 'var(--ggui-color-warning-200)',
  'noble gas': 'var(--ggui-color-primary-200)',
  'noble-gas': 'var(--ggui-color-primary-200)',
  lanthanide: 'var(--ggui-color-success-200)',
  actinide: 'var(--ggui-color-error-200)',
};

function getCategoryColor(category?: string): string {
  if (!category) return 'var(--ggui-color-surfaceVariant)';
  const normalized = category.toLowerCase().replace(/-/g, ' ');
  return CATEGORY_COLOR_MAP[category.toLowerCase()] ?? CATEGORY_COLOR_MAP[normalized] ?? 'var(--ggui-color-surfaceVariant)';
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [searchQuery, setSearchQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const safeElements = useMemo(() => props.elements ?? [], [props.elements]);

  const filteredElements = useMemo(() => {
    const query = searchQuery.trim().toLowerCase();
    if (!query) return safeElements;
    return safeElements.filter((element) => {
      const name = element.name?.toLowerCase() ?? '';
      const symbol = element.symbol?.toLowerCase() ?? '';
      return name.includes(query) || symbol.includes(query);
    });
  }, [safeElements, searchQuery]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === null) return null;
    return safeElements.find((element) => element.atomicNumber === selectedAtomicNumber) ?? null;
  }, [safeElements, selectedAtomicNumber]);

  const categories = useMemo(() => {
    const unique = new Set<string>();
    safeElements.forEach((element) => {
      if (element.category) unique.add(element.category);
    });
    return Array.from(unique).sort((a, b) => a.localeCompare(b));
  }, [safeElements]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={2}>Interactive Periodic Table</Heading>

        <Input
          label="Search elements by name or symbol"
          placeholder="Type e.g. Hydrogen or H"
          value={searchQuery}
          onChange={setSearchQuery}
        />

        {safeElements.length === 0 ? (
          <Alert variant="info" title="No element data">
            No elements were provided in props.elements.
          </Alert>
        ) : (
          <Card padding="var(--ggui-spacing-4)">
            {filteredElements.length === 0 ? (
              <Alert variant="warning" title="No matching elements">
                No elements match your current search.
              </Alert>
            ) : (
              <Box style={{ overflowX: 'auto' }}>
                <Box
                  role="grid"
                  aria-label="Periodic table elements"
                  style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(18, minmax(var(--ggui-spacing-12), 1fr))',
                    gap: 'var(--ggui-spacing-2)',
                    minWidth: 'calc(var(--ggui-spacing-12) * 18)',
                  }}
                >
                  {filteredElements.map((element, index) => (
                    <Card
                      key={`${element.atomicNumber ?? 'unknown'}-${element.symbol ?? 'x'}-${index}`}
                      role="gridcell"
                      aria-label={`${element.name ?? 'Unknown'} (${element.symbol ?? '?'}) atomic number ${element.atomicNumber ?? '-'}` }
                      as={Clickable}
                      onClick={() => setSelectedAtomicNumber(element.atomicNumber ?? null)}
                      hoverStyle={{
                        border: '2px solid var(--ggui-color-primary-500)',
                        boxShadow: 'var(--ggui-shape-shadow-md)',
                      }}
                      focusStyle={{
                        outline: '2px solid var(--ggui-color-primary-600)',
                        outlineOffset: '2px',
                      }}
                      padding="var(--ggui-spacing-2)"
                      border
                      radius="md"
                      style={{
                        minHeight: 'var(--ggui-spacing-12)',
                        background: getCategoryColor(element.category),
                        gridColumn: String(element.col ?? 'auto'),
                        gridRow: String(element.row ?? 'auto'),
                        border: selectedAtomicNumber === (element.atomicNumber ?? null)
                          ? '2px solid var(--ggui-color-primary-600)'
                          : '1px solid var(--ggui-color-outline)',
                        position: 'relative',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                      }}
                    >
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant)"
                        style={{ position: 'absolute', top: 'var(--ggui-spacing-1)', left: 'var(--ggui-spacing-1)' }}
                      >
                        {element.atomicNumber ?? '-'}
                      </Text>
                      <Text size="xl" weight="bold" align="center">
                        {element.symbol ?? '?'}
                      </Text>
                    </Card>
                  ))}
                </Box>
              </Box>
            )}
          </Card>
        )}

        <Card padding="var(--ggui-spacing-4)">
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={4}>Legend</Heading>
            <Row wrap gap="var(--ggui-spacing-2)">
              {categories.length === 0 ? (
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  No categories available.
                </Text>
              ) : (
                categories.map((category) => (
                  <Row key={category} gap="var(--ggui-spacing-2)" align="center" aria-label={`${category} category`}>
                    <Box
                      aria-hidden="true"
                      style={{
                        width: 'var(--ggui-spacing-3)',
                        height: 'var(--ggui-spacing-3)',
                        borderRadius: 'var(--ggui-shape-radius-sm)',
                        background: getCategoryColor(category),
                        border: '1px solid var(--ggui-color-outline)',
                      }}
                    />
                    <Text variant="caption">{category}</Text>
                  </Row>
                ))
              )}
            </Row>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4)">
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={4}>Element Details</Heading>
            {selectedElement ? (
              <Stack gap="var(--ggui-spacing-1)">
                <Text><Text is="span" weight="semibold">Name: </Text>{selectedElement.name ?? '-'}</Text>
                <Text><Text is="span" weight="semibold">Symbol: </Text>{selectedElement.symbol ?? '-'}</Text>
                <Text><Text is="span" weight="semibold">Atomic Number: </Text>{selectedElement.atomicNumber ?? '-'}</Text>
                <Text><Text is="span" weight="semibold">Atomic Weight: </Text>{selectedElement.atomicWeight ?? '-'}</Text>
                <Text><Text is="span" weight="semibold">Category: </Text>{selectedElement.category ?? '-'}</Text>
              </Stack>
            ) : (
              <Text color="var(--ggui-color-onSurfaceVariant)">
                Click an element to view details.
              </Text>
            )}
          </Stack>
