    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }
  const [activeTab, setActiveTab] = useState('description');
  const [quantity, setQuantity] = useState(1);

  const maxStock = useMemo(() => {
    const stockValue = typeof props.product?.stock === 'number' ? props.product.stock : 0;
    return stockValue > 0 ? stockValue : 1;
  }, [props.product?.stock]);

  useEffect(() => {
    if ((props.product?.stock ?? 0) <= 0) {
      setQuantity(1);
      return;
    }
    if (quantity > maxStock) {
      setQuantity(maxStock);
    }
  }, [props.product?.stock, quantity, maxStock]);

  const formattedPrice = useMemo(() => {
    const value = typeof props.product?.price === 'number' ? props.product.price : 0;
    const currency = props.product?.currency || '$';
    return `${currency}${value.toFixed(2)}`;
  }, [props.product?.price, props.product?.currency]);

  const ratingValue = useMemo(() => {
    const value = typeof props.product?.rating === 'number' ? props.product.rating : 0;
    if (value < 0) return 0;
    if (value > 5) return 5;
    return Math.round(value);
  }, [props.product?.rating]);

  const isOutOfStock = (props.product?.stock ?? 0) <= 0;
  const isLowStock = !isOutOfStock && (props.product?.stock ?? 0) <= 5;
  const hasValidProductId = typeof props.product?.id === 'string' && props.product.id.trim().length > 0;
  const specificationRows = useMemo(() => {
    const specs = Array.isArray(props.product?.specifications) ? props.product.specifications : [];
    return specs.map((item, index) => {
      if (item && typeof item === 'object' && !Array.isArray(item)) {
        const possibleKey = (item as Record<string, unknown>).key;
        const possibleLabel = (item as Record<string, unknown>).label;
        const possibleName = (item as Record<string, unknown>).name;
        const possibleValue = (item as Record<string, unknown>).value;
        const keyText =
          typeof possibleKey === 'string'
            ? possibleKey
            : typeof possibleLabel === 'string'
              ? possibleLabel
              : typeof possibleName === 'string'
                ? possibleName
                : `Specification ${index + 1}`;
        const valueText =
          typeof possibleValue === 'string' || typeof possibleValue === 'number'
            ? String(possibleValue)
            : 'N/A';
        return { id: `${keyText}-${index}`, specKey: keyText, specValue: valueText };
      }
      return { id: `spec-${index}`, specKey: `Specification ${index + 1}`, specValue: String(item ?? 'N/A') };
    });
  }, [props.product?.specifications]);

  const reviewRows = useMemo(() => {
    const reviews = Array.isArray(props.product?.reviews) ? props.product.reviews : [];
