        text: typeof record.text === 'string' ? record.text : 'No review text provided.',
        date: typeof record.date === 'string' ? record.date : 'Unknown date',
      };
    });
  }, [props.product?.reviews]);

  const handleIncrement = useCallback(() => {
    if (isOutOfStock) return;
    setQuantity((prev) => (prev < maxStock ? prev + 1 : prev));
  }, [isOutOfStock, maxStock]);

  const handleDecrement = useCallback(() => {
    setQuantity((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleAddToCart = useCallback(() => {
    if (isOutOfStock || !hasValidProductId) return;
    addToCart({ productId: props.product.id?.trim() || '', quantity });
  }, [addToCart, hasValidProductId, isOutOfStock, props.product?.id, quantity]);

