            >
              <Image
                src=""
                alt={`${props.product?.name || 'Unnamed Product'} image placeholder`}
                width="100%"
                height="100%"
                objectFit="contain"
                fallback={
                  <Stack justify="center" align="center" gap="var(--ggui-spacing-2)" style={{ minHeight: 'var(--ggui-spacing-12)' }}>
                    <Icon name="image" color="var(--ggui-color-primary-600)" size={32} />
                    <Text align="center" weight="semibold" color="var(--ggui-color-primary-800)">
                      {props.product?.name || 'Unnamed Product'}
