  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag
  const [messageList, setMessageList] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages || []);
  const [draft, setDraft] = useState<string>('');
  const [activeTyper, setActiveTyper] = useState<string>('');
  const [sendError, setSendError] = useState<string>('');
  const scrollRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setMessageList(props.messages || []);
  }, [props.messages]);

  useEffect(() => {
    if (!message.latest) {
      return;
    }
    setMessageList((prev) => [...prev, message.latest as StreamMessage]);
  }, [message.latest]);

  useEffect(() => {
    if (!typing.latest) {
      return;
    }
    if (typing.latest.active && typing.latest.sender && typing.latest.sender !== props.currentUser) {
      setActiveTyper(typing.latest.sender);
      return;
    }
    if (!typing.latest.active) {
      setActiveTyper('');
    }
  }, [typing.latest, props.currentUser]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messageList, activeTyper]);

  const groupedMessages = useMemo(() => {
    return (messageList || []).reduce<Array<{ sender: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }>>(
      (acc, current) => {
        const sender = current.sender || 'Unknown';
        const lastGroup = acc[acc.length - 1];
        if (!lastGroup || lastGroup.sender !== sender) {
          acc.push({ sender, items: [current] });
        } else {
          lastGroup.items.push(current);
        }
        return acc;
      },
