                {activeTyper} is typing...
              </Text>
            ) : null}
          </Stack>

          <Box
            padding="var(--ggui-spacing-3)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-md)"
          >
            <Box
              ref={scrollRef}
              style={{
                 maxHeight: 'calc(100vh - 260px)',
                overflowY: 'auto',
                padding: 'var(--ggui-spacing-2)',
                border: '1px solid var(--ggui-color-outlineVariant)',
                borderRadius: 'var(--ggui-shape-radius-md)',
                background: 'var(--ggui-color-surface)',
              }}
            >
              {(groupedMessages || []).length === 0 ? (
                <Stack align="center" justify="center" gap="var(--ggui-spacing-2)">
                  <Text color="var(--ggui-color-onSurfaceVariant)">No messages yet.</Text>
                </Stack>
              ) : (
                <Stack gap="var(--ggui-spacing-3)">
                  {(groupedMessages || []).map((group, groupIndex) => {
                    const isCurrentUser = group.sender === props.currentUser;
                    return (
                      <Stack key={`${group.sender}-${groupIndex}`} align={isCurrentUser ? 'end' : 'start'} gap="var(--ggui-spacing-1)">
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                          {group.sender}
                        </Text>
                        {(group.items || []).map((item, itemIndex) => (
                          <Box
                            key={`${group.sender}-${groupIndex}-${item.timestamp || itemIndex}` }
                            padding="var(--ggui-spacing-2)"
                            background={
                              isCurrentUser
                                ? 'var(--ggui-color-primary-600)'
                                : 'var(--ggui-color-surfaceVariant)'
                            }
                            borderRadius="var(--ggui-shape-radius-md)"
                            style={{ maxWidth: '75%' }}
                          >
                            <Stack gap="var(--ggui-spacing-1)">
                              <Text
                                variant="bodySmall"
                                color={isCurrentUser ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}
                              >
                                {item.text || ''}
                              </Text>
                              <Text
                                variant="caption"
                                color={
                                  isCurrentUser
                                    ? 'var(--ggui-color-primary-100)'
                                    : 'var(--ggui-color-onSurfaceVariant)'
                                }
                                align={isCurrentUser ? 'right' : 'left'}
                              >
                                {formatTime(item.timestamp)}
                              </Text>
                            </Stack>
                          </Box>
                        ))}
                      </Stack>
                    );
                  })}
                </Stack>
              )}
            </Box>
          </Box>

          <Divider margin="var(--ggui-spacing-2)" />

          {sendError ? (
            <Alert variant="error">{sendError}</Alert>
          ) : null}

