            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your name"
                  error={nameTouched && name.trim().length === 0 ? 'Name is required' : undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="you@example.com"
                  helperText="We’ll use this for account updates."
                  error={emailTouched && !emailValid ? 'Enter a valid email address' : undefined}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Choose an avatar</Text>
                  <Row gap="var(--ggui-spacing-3)" wrap>
                    {safeAvatars.map((option) => (
                      <Card
                        key={option}
                        as={Clickable}
                        onClick={() => setAvatar(option)}
                        padding="var(--ggui-spacing-3)"
                        radius="md"
                        border
                        style={{
                          borderColor: avatar === option ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                          background: avatar === option ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                        }}
                      >
                        <Text size="2xl" align="center">{option}</Text>
                      </Card>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  options={safeRoles.map((r) => ({ value: r, label: r }))}
                  placeholder="Select your role"
                  required
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label="Dark theme"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review & Confirm</Heading>
                <Card padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between"><Text variant="label">Name</Text><Text>{name || '—'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email</Text><Text>{email || '—'}</Text></Row>
                    <Row justify="between"><Text variant="label">Avatar</Text><Text>{avatar || '—'}</Text></Row>
                    <Row justify="between"><Text variant="label">Role</Text><Text>{role || '—'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Row justify="between"><Text variant="label">Theme</Text><Text>{theme}</Text></Row>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>

          <Divider margin="var(--ggui-spacing-4)" />
          <Row justify="between" align="center">
            <Button variant="outline" onClick={handleBack} disabled={step === 1}>
              Back
            </Button>
            <Row gap="var(--ggui-spacing-2)">
              {step < 3 && (
                <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>
                  Next
                </Button>
              )}
              {step === 3 && (
                <>
                  <Button variant="secondary" onClick={handleBack}>
                    Go Back
                  </Button>
                  <Button variant="primary" onClick={handleComplete}>
                    Complete Setup
                  </Button>
                </>
              )}
            </Row>
          </Row>
        </Card>
      </Stack>
    </Container>

  );
}
